import{_ as n,c as t,o as a,a1 as i}from"./chunks/framework.DDNAyvCW.js";const s="/assets/ec2-1.D6GQvE-u.png",o="/assets/ec2-2.CXEvv6ct.png",r="/assets/ec2-3.BcTAh1u2.png",f=JSON.parse('{"title":"Best Practices for Secure Private Connectivity and Management on EC2","description":"","frontmatter":{"title":"Best Practices for Secure Private Connectivity and Management on EC2","author":"AWS Blogs","date":"2026-3-27","comment":false,"category":"Security","tags":["Security","Identity","Compliance","ZeroTrust","BestPractices","AWS"],"blog":"post","aside":"left","sidebar":false,"prev":false,"next":false},"headers":[],"relativePath":"blog/posts/ec2-connect.md","filePath":"blog/posts/ec2-connect.md"}'),l={name:"blog/posts/ec2-connect.md"};function c(p,e,u,h,d,m){return a(),t("div",null,e[0]||(e[0]=[i('<p>This article introduces the integration of Chaterm, with AWS EC2 Instance Connect Endpoint to address operational challenges in private subnets. Traditional approaches require VPNs or bastion hosts,whereas EICE leverages IAM-based authentication to establish secure connections without public IP addresses. Chaterm wraps the EICE capability with cross-platform auto-adaptation and a visual interface.</p><hr><h2 id="_1-introduction" tabindex="-1">1. Introduction <a class="header-anchor" href="#_1-introduction" aria-label="Permalink to &quot;1. Introduction&quot;">​</a></h2><p>When building enterprise-grade AWS architectures, we typically follow the best practice of “layered security”: deploying databases, middleware, and core application servers in Private Subnets, without assigning public IPs.</p><p>However, this highly secure architectural design often creates a “last mile” challenge for day-to-day operations:</p><ul><li><strong>Complex Connectivity:</strong> Operations personnel either need to configure complex VPNs or set up and maintain dedicated EC2 jump servers (Bastion Hosts).</li><li><strong>Fragmented Environments:</strong> Different local OS environments across team members (Windows/Mac/Linux) lead to chaotic SSH key management, inconsistent AWS CLI versions, and high onboarding costs for new team members.</li><li><strong>Hindered Intelligence:</strong> In the era of AIOps, many locally-running AI-assisted tools cannot penetrate complex network tunnels to directly perform intelligent diagnostics on instances within private subnets.</li></ul><p>We will introduce an open-source intelligent terminal tool deeply integrated with AWS native capabilities — Chaterm, and demonstrate how it combines with AWS EC2 Instance Connect Endpoint (EICE) to achieve “one-click direct connection” and AI empowerment for private resources without exposing public ports.</p><h2 id="_2-what-is-chaterm" tabindex="-1">2. What is Chaterm? <a class="header-anchor" href="#_2-what-is-chaterm" aria-label="Permalink to &quot;2. What is Chaterm?&quot;">​</a></h2><p>Chaterm is an open-source intelligent terminal tool developed by IntSig. Unlike traditional SSH clients, its core philosophy is “Chat with Terminal”. It is not just a connection tool — it has a powerful built-in AI Agent that can understand terminal context, help developers explain errors, generate commands, and even automatically write scripts.</p><p>In its latest version, Chaterm has launched an AWS EC2 plugin that fundamentally transforms the operations experience for private cloud resources through deep integration with AWS’s modern connectivity technologies.</p><h2 id="_3-aws-ec2-instance-connect-endpoint-—-technical-deep-dive" tabindex="-1">3. AWS EC2 Instance Connect Endpoint — Technical Deep Dive <a class="header-anchor" href="#_3-aws-ec2-instance-connect-endpoint-—-technical-deep-dive" aria-label="Permalink to &quot;3. AWS EC2 Instance Connect Endpoint — Technical Deep Dive&quot;">​</a></h2><h3 id="_3-1-why-is-this-solution-more-advanced-than-traditional-bastion-hosts" tabindex="-1">3.1 Why is this solution more advanced than traditional bastion hosts? <a class="header-anchor" href="#_3-1-why-is-this-solution-more-advanced-than-traditional-bastion-hosts" aria-label="Permalink to &quot;3.1 Why is this solution more advanced than traditional bastion hosts?&quot;">​</a></h3><p>The EC2 Instance Connect Endpoint (EICE) feature, launched by AWS in 2023, elevates connection control from the “network layer” to the “identity layer”.</p><ul><li><strong>No Public IP Required:</strong> EICE is a logical interface (Endpoint) deployed within the user’s VPC. It acts like an “invisible gateway”, allowing SSH traffic to reach target instances directly through AWS’s private network tunnel.</li><li><strong>Identity as the Defense Line:</strong> Traditional connectivity relies on IP whitelisting or SSH key distribution, whereas EICE relies on AWS IAM (Identity and Access Management) for authentication. This means all connection requests go through IAM permission verification and are audit-logged by CloudTrail.</li><li><strong>Zero Trust Architecture:</strong> EC2 instance security groups no longer need to open port 22 to the public internet (0.0.0.0/0) — they only need to allow traffic from the subnet where EICE is located.</li></ul><h2 id="_4-the-solution-dual-advantages-of-chaterm-aws-eice" tabindex="-1">4. The Solution: Dual Advantages of Chaterm + AWS EICE <a class="header-anchor" href="#_4-the-solution-dual-advantages-of-chaterm-aws-eice" aria-label="Permalink to &quot;4. The Solution: Dual Advantages of Chaterm + AWS EICE&quot;">​</a></h2><p>Chaterm’s AWS plugin encapsulates EICE’s powerful capabilities behind a clean UI, primarily solving the following problems:</p><h3 id="_4-1-simpler-connections-with-adaptive-environment" tabindex="-1">4.1 Simpler Connections with Adaptive Environment <a class="header-anchor" href="#_4-1-simpler-connections-with-adaptive-environment" aria-label="Permalink to &quot;4.1 Simpler Connections with Adaptive Environment&quot;">​</a></h3><p>Traditionally, using EICE requires memorizing lengthy AWS CLI commands (such as aws ec2-instance-connect open-tunnel). Chaterm’s plugin has a built-in cross-platform (Windows/macOS/Linux) AWS CLI environment that automatically completes dependency adaptation during plugin installation.</p><p>After configuring AWS credentials (Access Key / Secret Key), the plugin will automatically discover resources through the AWS API. Users simply click on an instance in the visual list, and the plugin will automatically generate the SSH ProxyCommand and establish an encrypted tunnel in the background</p><p><img src="'+s+'" alt=""></p><h3 id="_4-2-unlocking-the-full-potential-of-ai-operations" tabindex="-1">4.2 Unlocking the Full Potential of AI Operations <a class="header-anchor" href="#_4-2-unlocking-the-full-potential-of-ai-operations" aria-label="Permalink to &quot;4.2 Unlocking the Full Potential of AI Operations&quot;">​</a></h3><p>This is the biggest highlight of this solution. Previously, after connecting to a private network EC2 instance, local AI tools were often “out of reach”.</p><p>Since Chaterm establishes a transparent tunnel, its built-in AI Agent can operate private network EC2 instances as if operating a local machine. Once connected, Chaterm’s full AI capabilities take effect immediately:</p><ul><li><strong>Intelligent Inspection:</strong> You can directly ask the AI: “Help me check the disk usage.” The AI will automatically execute df -h and present the output in a formatted manner.</li><li><strong>Fault Diagnosis:</strong> Describe the symptoms (e.g., “Web service response is slow”), and the AI will automatically execute a series of diagnostic commands like top, ps, netstat, and generate an analysis report. Compared to manually typing commands one by one, the efficiency improvement is significant.</li><li><strong>Batch Operations:</strong> Using Chaterm’s multi-session feature, you can simultaneously select 10 private network servers and have the AI assist with batch configuration update distribution.</li></ul><p><img src="'+o+`" alt=""></p><h2 id="_5-practical-guide-how-to-configure" tabindex="-1">5. Practical Guide: How to Configure <a class="header-anchor" href="#_5-practical-guide-how-to-configure" aria-label="Permalink to &quot;5. Practical Guide: How to Configure&quot;">​</a></h2><p>To ensure security, we will follow AWS’s Least Privilege Principle for configuration.</p><h3 id="_5-1-step-1-aws-side-configuration-one-time-setup" tabindex="-1">5.1 Step 1: AWS-Side Configuration (One-Time Setup) <a class="header-anchor" href="#_5-1-step-1-aws-side-configuration-one-time-setup" aria-label="Permalink to &quot;5.1 Step 1: AWS-Side Configuration (One-Time Setup)&quot;">​</a></h3><h4 id="_5-1-1-create-an-ec2-instance-connect-endpoint" tabindex="-1">5.1.1 Create an EC2 Instance Connect Endpoint <a class="header-anchor" href="#_5-1-1-create-an-ec2-instance-connect-endpoint" aria-label="Permalink to &quot;5.1.1 Create an EC2 Instance Connect Endpoint&quot;">​</a></h4><p>Create an EICE in the VPC console or using CLI, ensuring you select the target private subnet:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>aws ec2 create-instance-connect-endpoint \\</span></span>
<span class="line"><span>--region cn-north-1 \\</span></span>
<span class="line"><span>--subnet-id subnet-xxxxxx \\</span></span>
<span class="line"><span>--security-group-ids sg-xxxxxx \\</span></span>
<span class="line"><span>--preserve-client-ip</span></span></code></pre></div><h3 id="_5-1-2-configure-security-groups" tabindex="-1">5.1.2 Configure Security Groups <a class="header-anchor" href="#_5-1-2-configure-security-groups" aria-label="Permalink to &quot;5.1.2 Configure Security Groups&quot;">​</a></h3><p>Modify the target EC2’s security group to only allow SSH (port 22) traffic from the EICE security group ID.</p><h3 id="_5-1-3-create-a-dedicated-iam-user-and-policy" tabindex="-1">5.1.3 Create a Dedicated IAM User and Policy <a class="header-anchor" href="#_5-1-3-create-a-dedicated-iam-user-and-policy" aria-label="Permalink to &quot;5.1.3 Create a Dedicated IAM User and Policy&quot;">​</a></h3><p>We strongly recommend not directly using administrator-privileged AK/SK. Please create a dedicated IAM user and grant only the following fine-grained permissions (restricting tunnel establishment to specific resources and ports):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>    &quot;Version&quot;: &quot;2012-10-17&quot;,</span></span>
<span class="line"><span>    &quot;Statement&quot;: [</span></span>
<span class="line"><span>        {</span></span>
<span class="line"><span>            &quot;Effect&quot;: &quot;Allow&quot;,</span></span>
<span class="line"><span>            &quot;Action&quot;: [</span></span>
<span class="line"><span>                &quot;ec2:DescribeInstances&quot;,</span></span>
<span class="line"><span>                &quot;ec2:DescribeSubnets&quot;,</span></span>
<span class="line"><span>                &quot;ec2:DescribeInstanceConnectEndpoints&quot;</span></span>
<span class="line"><span>            ],</span></span>
<span class="line"><span>            &quot;Resource&quot;: &quot;*&quot;</span></span>
<span class="line"><span>        },</span></span>
<span class="line"><span>        {</span></span>
<span class="line"><span>            &quot;Effect&quot;: &quot;Allow&quot;,</span></span>
<span class="line"><span>            &quot;Action&quot;: &quot;ec2-instance-connect:OpenTunnel&quot;,</span></span>
<span class="line"><span>            &quot;Resource&quot;: &quot;arn:aws:ec2:*:*:instance-connect-endpoint/*&quot;,</span></span>
<span class="line"><span>            &quot;Condition&quot;: {</span></span>
<span class="line"><span>                &quot;NumericEquals&quot;: {</span></span>
<span class="line"><span>                    &quot;ec2-instance-connect:remotePort&quot;: &quot;22&quot;</span></span>
<span class="line"><span>                }</span></span>
<span class="line"><span>            }</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>    ]</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="_5-2-step-2-chaterm-side-configuration-only-takes-2-minutes" tabindex="-1">5.2 Step 2: Chaterm-Side Configuration (Only Takes 2 Minutes) <a class="header-anchor" href="#_5-2-step-2-chaterm-side-configuration-only-takes-2-minutes" aria-label="Permalink to &quot;5.2 Step 2: Chaterm-Side Configuration (Only Takes 2 Minutes)&quot;">​</a></h3><p>Open Chaterm, search for and install the “AWS EC2” plugin in the plugin marketplace. Go to plugin settings, and enter the Access Key (AK), Secret Key (SK), and target Region (e.g., cn-north-1) of the IAM user created in the previous step. Return to the main interface — your private network instance list will load automatically. Select an instance and click “Connect”.</p><p><img src="`+r+'" alt=""></p><h2 id="_6-summary" tabindex="-1">6. Summary <a class="header-anchor" href="#_6-summary" aria-label="Permalink to &quot;6. Summary&quot;">​</a></h2><p>Through deep integration with AWS EC2 Instance Connect Endpoint, Chaterm provides developers with a connection solution that is both enterprise security-compliant (no public IP, IAM auditing) and delivers an excellent user experience (no bastion hosts, AI-empowered).</p><p>If you are looking for a more secure and intelligent way to manage your AWS private subnet resources, Chaterm is undoubtedly one of the best practices available today.</p><h2 id="original" tabindex="-1">Original <a class="header-anchor" href="#original" aria-label="Permalink to &quot;Original&quot;">​</a></h2><p><a href="https://aws.amazon.com/cn/blogs/china/bastion-using-aws-eice-ec2-instance-connect-endpoint-chaterm-implement-subnet-security-intelligent-en/" target="_blank" rel="noreferrer">https://aws.amazon.com/cn/blogs/china/bastion-using-aws-eice-ec2-instance-connect-endpoint-chaterm-implement-subnet-security-intelligent-en/</a></p>',44)]))}const b=n(l,[["render",c]]);export{f as __pageData,b as default};
